starterCode.javascript:
const titulo = document.querySelector('h2');
const cuadrado = document.querySelector('.cuadrado');
const texto = document.querySelector('#texto');

// Define miFuncion_1, miFuncion_2 y miFuncion_3.

targetCode.css:
body {
  margin: 0;
  min-height: 100vh;
  display: grid;
  place-items: center;
  background: #f7f3eb;
  font-family: Georgia, serif;
}

main {
  text-align: center;
}

h2,
#texto {
  cursor: pointer;
}

.cuadrado {
  width: 100px;
  height: 100px;
  margin: 12px auto;
  background: blue;
  border: 4px solid #1f2937;
}

.miClase {
  width: 50px;
  height: 50px;
  background: red;
  border-style: dotted;
}

targetCode.javascript:
function miFuncion_1() {
  texto.textContent = texto.textContent.trim() === 'DAW' ? 'Compostela' : 'DAW';
}

function miFuncion_2() {
  cuadrado.classList.toggle('miClase');
}

function miFuncion_3() {
  const esPequeno = cuadrado.classList.contains('miClase');
  const colorActual = getComputedStyle(cuadrado).backgroundColor;
  const esVerde = colorActual === 'rgb(0, 128, 0)' || cuadrado.style.backgroundColor === 'green';

  if (esPequeno) {
    cuadrado.style.backgroundColor = esVerde ? 'red' : 'green';
  } else {
    cuadrado.style.backgroundColor = esVerde ? 'blue' : 'green';
  }
}

cuadrado.addEventListener('mouseover', miFuncion_1);
texto.addEventListener('dblclick', miFuncion_2);
titulo.addEventListener('click', miFuncion_3);
